'use client';
import { Button } from '@/components/ui/button';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuGroup,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger
} from '@/components/ui/dropdown-menu';
import { UserAvatarProfile } from '@/components/user-avatar-profile';
import { useRouter } from 'next/navigation';
import { useIsMounted } from '@/hooks/use-is-mounted';
import { useAccount, useDisconnect, useChainId } from 'wagmi';
import { ConnectButton } from '@rainbow-me/rainbowkit';

export function UserNav() {
  const router = useRouter();
  const mounted = useIsMounted();
  const { address, isConnected } = useAccount();
  const { disconnect } = useDisconnect();
  const chainId = useChainId();

  // Mapping some common chain IDs manually if needed, but RainbowKit shows chain info
  const network = chainId === 11155111 ? 'Sepolia' : (chainId ? `Chain ${chainId}` : 'Unknown');

  const wallet = isConnected ? { address: address as string, network, isConnected } : null;

  if (!mounted) return null;

  if (!isConnected) {
    return (
      <ConnectButton.Custom>
        {({ openConnectModal, mounted: connectMounted }) => {
          return (
            <div
              {...(!connectMounted && {
                'aria-hidden': true,
                style: {
                  opacity: 0,
                  pointerEvents: 'none',
                  userSelect: 'none',
                },
              })}
            >
              <Button
                onClick={openConnectModal}
                variant="default"
                className="bg-primary hover:bg-primary/90 text-primary-foreground font-medium rounded-full px-5 transition-all active:scale-95"
              >
                Connect Wallet
              </Button>
            </div>
          );
        }}
      </ConnectButton.Custom>
    );
  }

  const truncatedAddress = address
    ? `${address.slice(0, 6)}...${address.slice(-4)}`
    : 'No Wallet Linked';

  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button variant='ghost' className='relative h-8 w-8 rounded-full focus-visible:ring-primary/20'>
          <UserAvatarProfile wallet={wallet} />
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent
        className='w-56'
        align='end'
        sideOffset={10}
        forceMount
      >
        <DropdownMenuLabel className='font-normal'>
          <div className='flex flex-col space-y-1'>
            <p className='text-sm leading-none font-medium'>
              {truncatedAddress}
            </p>
            <p className='text-muted-foreground text-xs leading-none uppercase tracking-wider'>
              {network}
            </p>
          </div>
        </DropdownMenuLabel>
        <DropdownMenuSeparator />
        <DropdownMenuGroup>
          <DropdownMenuItem onClick={() => router.push('/dashboard/profile')}>
            Profile
          </DropdownMenuItem>
          <DropdownMenuItem>Billing</DropdownMenuItem>
          <DropdownMenuItem onClick={() => router.push('/dashboard/settings')}>Settings</DropdownMenuItem>
        </DropdownMenuGroup>
        <DropdownMenuSeparator />
        <DropdownMenuItem
          className="text-destructive focus:bg-destructive/10 focus:text-destructive"
          onClick={() => disconnect()}
        >
          Disconnect Wallet
        </DropdownMenuItem>
      </DropdownMenuContent>
    </DropdownMenu>
  );
}
